import requests, sys
from concurrent.futures import ThreadPoolExecutor
requests.packages.urllib3.disable_warnings()
base='http://localhost:80/'
paths = [
 'index.php','index.html','upload/','uploads/','images/','css/','js/','assets/','static/','include/','inc/','lib/','vendor/','composer.json','composer.lock','server-status','.git/','.svn/','.hg/','backup/','bak/','old/','temp/','tmp/','logs/','log/','.env','phpinfo.php','info.php','api/','api.php','admin/','admin.php','dashboard/','panel/','status','health','version','README','README.md','readme.txt','license','LICENSE','.htaccess','.htpasswd','sitemap.xml','robots.txt','feed','help','upload.php','uploader.php','file.php','upload/index.php'
]
seen=[]
results=[]

def fetch(p):
    try:
        r = requests.get(base+p, timeout=5, allow_redirects=False)
        return p, r.status_code, r.headers.get('Location'), r.headers.get('Content-Type'), len(r.content)
    except Exception as e:
        return p, 'ERR', str(e), None, 0

with ThreadPoolExecutor(max_workers=8) as ex:
    for p, code, loc, ct, ln in ex.map(fetch, paths):
        if code in (200,301,302,403):
            results.append((p, code, loc, ct, ln))

for row in results:
    print(row)

